+// MARK: - Input View
+
+struct InputView: View {
+    @ObservedObject var viewModel: ZellViewModel
+    @State private var prompt: String = ""
+
+    var body: some View {
+        VStack(spacing: 8) {
+            HStack(spacing: 12) {
+                // Use TextEditor for better keyboard handling
+                ZStack(alignment: .topLeading) {
+                    if prompt.isEmpty {
+                        Text("Ask anything...")
+                            .foregroundColor(.white.opacity(0.4))
+                            .padding(.horizontal, 4)
+                            .padding(.vertical, 8)
+                    }
+
+                    TextEditor(text: $prompt)
+                        .font(.system(size: 15))
+                        .foregroundColor(.white)
+                        .scrollContentBackground(.hidden)
+                        .background(Color.clear)
+                        .frame(minHeight: 40, maxHeight: 80)
+                }
+                .padding(12)
+                .background(Color.white.opacity(0.08))
+                .cornerRadius(12)
+
+                // Send button
+                Button(action: submit) {
+                    Image(systemName: "arrow.up.circle.fill")
+                        .font(.system(size: 32))
+                        .foregroundColor(.purple)
+                }
+                .buttonStyle(.borderless)
+                .disabled(prompt.isEmpty || viewModel.isProcessing)
+            }
+
+            // Hints
+            HStack {
+                Text("⌘↵ to send")
+                    .font(.system(size: 11))
+                    .foregroundColor(.white.opacity(0.4))
+                Spacer()
+            }
+        }
+        .padding(16)
+        .background(.ultraThinMaterial)
+        .onExitCommand { } // Prevent escape from closing
+    }
+
+    private func submit() {
+        guard !prompt.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
+        viewModel.sendPrompt(prompt.trimmingCharacters(in: .whitespacesAndNewlines))
+        prompt = ""
+    }
+}
+
+// MARK: - ViewModel
+
+@MainActor
+class ZellViewModel: ObservableObject {
+    @Published var models: [String] = []
+    @Published var selectedModel: String = ""
+    @Published var status: String = "Ready"
+    @Published var isProcessing: Bool = false
+
+    weak var terminalView: TerminalView?
+    private let zellBridge = ZellBridge()
+
+    init() {
+        loadModels()
+        showWelcome()
+    }
+
+    private func loadModels() {
+        models = zellBridge.listModels()
+        if models.isEmpty {
+            models = ["No models found"]
+        }
+        selectedModel = models.first ?? ""
+    }
+
+    private func showWelcome() {
+        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) { [weak self] in
+            self?.terminalView?.appendOutput("Welcome to Zell!\n\n")
+            if self?.zellBridge.isAvailable == false {
+                self?.terminalView?.appendOutput("⚠️  zell binary not found. Build it first:\n")
+                self?.terminalView?.appendOutput("   cd ~/Downloads/repos/zell && zig build\n\n")
+            }
+        }
+    }
+
+    func sendPrompt(_ prompt: String) {
+        guard !isProcessing else { return }
+
+        isProcessing = true
+        status = "Thinking..."
+
+        // Show user message
+        terminalView?.appendOutput("\n\u{001B}[1;36mYou:\u{001B}[0m \(prompt)\n\n")
+        terminalView?.appendOutput("\u{001B}[1;32mAssistant:\u{001B}[0m ")
+
+        // Run zell
+        zellBridge.run(
+            prompt: prompt,
+            model: selectedModel.contains("No models") ? nil : selectedModel,
+            onOutput: { [weak self] output in
+                self?.terminalView?.appendOutput(output)
+            },
+            onComplete: { [weak self] error in
+                if let error = error {
+                    self?.terminalView?.appendOutput("\n\u{001B}[1;31mError:\u{001B}[0m \(error.localizedDescription)\n")
+                    self?.status = "Error"
+                } else {
+                    self?.terminalView?.appendOutput("\n")
+                    self?.status = "Ready"
+                }
+                self?.isProcessing = false
+            }
+        )
+    }
+
+    func newChat() {
+        zellBridge.cancel()
+        terminalView?.clear()
+        terminalView?.appendOutput("Chat cleared.\n\n")
+    }
+
+    func clearTerminal() {
+        terminalView?.clear()
     }
 }

